    public function beforeSave($insert) {
        $file = UploadedFile::getInstance($this, 'Banner_large');
        if (!empty($file) && $file !== NULL) {
            if ($file->type == 'image/png' || $file->type == 'image/jpeg') {
                $upload = dirname(dirname(__DIR__)) . '/frontend/web/uploads/';
                $folder = '/images/'.date('Y').'/'.date('m').'/';
                $path = $upload . $folder;
                $ext = $file->getExtension();
                $filename = '/' . Helper::alias(explode('.', $file->name)[0]) . '.' . $ext;
                $filename_medium = '/' . Helper::alias(explode('.', $file->name)[0]) . '_m.' . $ext;

                if (!file_exists($path)) {
                    FileHelper::createDirectory($path);
                }

                if ($file->saveAs($path . $filename)) {
                    $this->Banner_large = '/uploads' . $folder . $filename;
                    $this->Banner_small = '/uploads' . $folder . $filename_medium;
                }

                $imagine = Image::getImagine()
                    ->open($path . $filename)
                    ->thumbnail(new Box(800, 800))
                    ->save($path . $filename, ['quality' => 100]);
                Image::thumbnail($path . $filename, 800, 400)->save($path . $filename, ['quality' => 100]);
                $imagine = Image::getImagine()
                    ->open($path . $filename)
                    ->thumbnail(new Box(400, 400))
                    ->save($path . $filename_medium, ['quality' => 100]);
                Image::thumbnail($path . $filename_medium, 400, 200)->save($path . $filename_medium, ['quality' => 100]);
            } else {
                $this->Banner_large = $this->getOldAttribute('Banner_large');
                $this->Banner_small = $this->getOldAttribute('Banner_small');
            }
        }
        return parent::beforeSave($insert);
    }

