    public static function getSuggestCourse($ids,$limit = 0,$notInIds = []){
        $query = self::find()->select('course.*, teacher_profile.image,teacher_profile.FullName')->innerJoin('teacher_profile','teacher_profile.ID = course.Profile_id')->where(['course.ID' => $ids])->andWhere(['course.Status' => self::STATUS_PUBLISH])->andWhere(['NOT IN','course.ID',$notInIds ]);
